// ============================================================
// PFCスコアリングで目標に近い3品を選ぶ関数
// ★ 修正ポイント:
//   1. moodフィルタが厳しすぎて候補不足の場合、'any'メニューでフォールバック
//   2. g?t系（軽食）のtimeSlotから夜を除外（夜に低カロリー軽食が出ない）
//   3. カロリー乖離ペナルティを追加（targetCalと大きくズレるメニューを弾く）
//   4. 夜に200kcal未満のメニューが出ないよう強いペナルティ
// ============================================================

function selectMeals(targetCal, targetP, targetF, targetC, goal, location, mood, excludeIds = [], timeOfDay = null, proteinWeight = 1.0, subWeight = null, hunger = null) {

  // ── ① プライマリフィルタ（mood一致 + location一致） ──
  const primaryFilter = (meal) => {
    if (!meal.goals.includes(goal)) return false;
    if (excludeIds.includes(meal.id)) return false;
    if (timeOfDay && meal.timeSlot && !meal.timeSlot.includes(timeOfDay)) return false;
    if (mood && mood !== '特になし') {
      return meal.mood === mood && meal.locations.includes(location);
    }
    if (meal.mood === 'お酒を飲みたい') return false;
    if (meal.mood === '揚げ物を食べたい') return false;
    if (meal.mood === '間食したい') return false;
    return meal.locations.includes(location);
  };

  let filtered = MEAL_DB.filter(primaryFilter);

  // ── ② フォールバック: 候補が3未満の場合は'any'moodのメニューで補完 ──
  if (filtered.length < 3) {
    const fallbackFilter = (meal) => {
      if (!meal.goals.includes(goal)) return false;
      if (excludeIds.includes(meal.id)) return false;
      if (timeOfDay && meal.timeSlot && !meal.timeSlot.includes(timeOfDay)) return false;
      if (meal.mood === 'お酒を飲みたい') return false;
      if (meal.mood === '揚げ物を食べたい') return false;
      if (meal.mood === '間食したい') return false;
      if (meal.mood !== 'any') return false;
      return meal.locations.includes(location);
    };
    const existingIds = new Set(filtered.map(m => m.id));
    const fallback = MEAL_DB.filter(fallbackFilter).filter(m => !existingIds.has(m.id));
    filtered = [...filtered, ...fallback];
  }

  // ── 2食時: ベースmealが軽すぎるとscaleしても不足するため500kcal以上を優先 ──
  if (targetCal >= 700) {
    const substantial = filtered.filter(m => m.cal >= 500);
    if (substantial.length >= 3) filtered = substantial;
  }

  // ── ③ それでも候補なし → 空を返す ──
  if (filtered.length === 0) return [];

  // ── お酒moodのPFC目標調整 ──
  let targetPPct = (targetP * 4) / targetCal * 100;
  let targetFPct = (targetF * 9) / targetCal * 100;
  let targetCPct = (targetC * 4) / targetCal * 100;
  if (mood === 'お酒を飲みたい') {
    targetPPct = Math.min(targetPPct, 38);
    targetCPct = Math.max(targetCPct, 35);
    targetFPct = Math.min(targetFPct, 27);
  }

  const heavyWords = ['ラーメン', 'カレー', 'カツ', 'コロッケ', '唐揚げ', 'から揚げ', 'フライ', '天丼', '焼肉', 'こってり', '二郎'];

  // ── ④ スコアリング ──
  const scored = filtered.map(meal => {
    const pfcCal = meal.p * 4 + meal.f * 9 + meal.c * 4;
    if (pfcCal <= 0) return { meal, score: 9999 };

    const mealPPct = (meal.p * 4) / pfcCal * 100;
    const mealFPct = (meal.f * 9) / pfcCal * 100;
    const mealCPct = (meal.c * 4) / pfcCal * 100;

    let score =
      Math.abs(mealPPct - targetPPct) * proteinWeight +
      Math.abs(mealFPct - targetFPct) * 0.8 +
      Math.abs(mealCPct - targetCPct) * 0.4;

    // ── 脂質グラム乖離ペナルティ（target.fから大幅に低い候補を抑制） ──
    if (targetF > 0) {
      const fGapRatio = meal.f / targetF;
      if (fGapRatio < 0.4) score += 15;       // target.fの40%未満 → 強いペナルティ
      else if (fGapRatio < 0.6) score += 8;    // 60%未満 → 中程度
      else if (fGapRatio < 0.75) score += 3;   // 75%未満 → 軽いペナルティ
    }

    // ── カロリー乖離ペナルティ（空腹度で許容幅を調整） ──
    // 空腹度 → 許容上限/下限の倍率（targetCalは変えず選択範囲だけ変える）
    const hungerTolerance = {
      'かなり空腹':           { upper: 1.15, lower: 0.85 },  // +15% / -15%
      '少し空腹':             { upper: 1.05, lower: 0.90 },  // +5%  / -10%
      'そこまで空腹じゃない': { upper: 0.95, lower: 0.80 },  // -5%  / -20%
      'なんとなく食べたい':   { upper: 0.90, lower: 0.75 }   // -10% / -25%
    };
    const tol = hungerTolerance[hunger] || { upper: 1.0, lower: 0.85 };
    const calRatio = meal.cal / targetCal;
    if (calRatio < tol.lower * 0.6) score += 25;       // 極端に少ない
    else if (calRatio < tol.lower)   score += 12;       // 許容下限を下回る
    else if (calRatio > tol.upper * 1.3) score += 15;   // 極端に多い
    else if (calRatio > tol.upper)   score += 8;         // 許容上限を超える

    // ── 時間帯ペナルティ ──
    if (timeOfDay === '朝') {
      const isHeavy = heavyWords.some(w => meal.name.includes(w));
      if (isHeavy) score += 20;
      if (mealFPct > 30) score += 10;
    } else if (timeOfDay === '夜') {
      if (mealFPct > 35) score += 15;
      if (mealCPct > 70) score += 10;
      if (meal.cal < 250) score += 30; // 夜に軽食レベルを弾く
    } else if (timeOfDay === '間食') {
      if (meal.cal > 400) score += 20;
    }

    // ── 空腹感スコア調整 ──
    if (hunger === 'かなり空腹') {
      if (mealPPct > 28) score -= 5;
      // targetCalより大幅に低い候補を抑制（空腹時に軽食が出るのを防ぐ）
      if (calRatio < 0.75) score += 12;
      else if (calRatio < 0.85) score += 5;
    } else if (hunger === 'そこまで空腹じゃない' || hunger === 'なんとなく食べたい') {
      if (meal.cal < targetCal) score -= 5;
      if (meal.cal > targetCal * 1.2) score += 8;
    }

    // ── sub別スコア調整 ──
    if (subWeight) {
      if (subWeight.pBonus   && mealPPct > 30) score -= subWeight.pBonus;
      if (subWeight.fPenalty && mealFPct > 25) score += subWeight.fPenalty;
      if (subWeight.cBonus   && mealCPct > 50) score -= subWeight.cBonus;
      if (subWeight.cPenalty && mealCPct > 55) score += subWeight.cPenalty;
      if (subWeight.calBonus   && meal.cal > targetCal)       score -= subWeight.calBonus;
      if (subWeight.calPenalty && meal.cal > targetCal * 1.1) score += subWeight.calPenalty;
    }

    // ── 最低必要量チェック（身体条件から逆算された必要量を下回る候補を抑制） ──
    // ① カロリー成立ライン: targetCalの60%未満は1食として不足
    if (targetCal > 0 && meal.cal / targetCal < 0.60) {
      score += 25;
    }
    // ② タンパク質成立ライン: targetPの50%未満は筋肉維持・代謝維持に不足
    if (targetP > 0 && meal.p / targetP < 0.50) {
      score += 20;
    }
    // ②-b タンパク質不足の連続ペナルティ: 不足gに比例してスコア悪化
    if (targetP > 0 && meal.p < targetP) {
      const pShortage = targetP - meal.p;
      score += pShortage * 0.5;
    }
    // ③ かなり空腹時の成立ライン強化: 70%未満も不足と判断
    if (hunger === 'かなり空腹' && targetCal > 0 && meal.cal / targetCal < 0.70) {
      score += 15;
    }

    return { meal, score };
  });

  scored.sort((a, b) => a.score - b.score);
  return scored.slice(0, 3).map(s => s.meal);
}